<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu Desktop</title>
<style>
  *, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }

  body {
    overflow: hidden;
    font-family: 'Segoe UI', Ubuntu, Cantarell, sans-serif;
    user-select: none;
    height: 100vh;
    width: 100vw;
  }

  /* ── Desktop ── */
  #desktop {
    position: fixed;
    top: 0; left: 0; right: 0; bottom: 0;
    background: linear-gradient(135deg, #1a1a2e 0%, #16213e 40%, #0f3460 100%);
    z-index: 0;
  }

  /* ── Top Bar ── */
  #topbar {
    position: fixed;
    top: 0; left: 0; right: 0;
    height: 28px;
    background: rgba(15, 15, 15, 0.95);
    color: #ddd;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 14px;
    font-size: 13px;
    z-index: 1000;
    backdrop-filter: blur(6px);
    border-bottom: 1px solid rgba(255,255,255,0.07);
  }
  #topbar .left { display: flex; align-items: center; gap: 18px; }
  #topbar .center { color: #aaa; font-size: 12px; letter-spacing: 0.3px; }
  #topbar .right { display: flex; align-items: center; gap: 14px; }

  /* ── Dock / Taskbar ── */
  #taskbar {
    position: fixed;
    left: 0; top: 28px; bottom: 0;
    width: 56px;
    background: rgba(15, 15, 15, 0.75);
    backdrop-filter: blur(10px);
    display: flex;
    flex-direction: column;
    align-items: center;
    padding-top: 12px;
    gap: 8px;
    z-index: 999;
    border-right: 1px solid rgba(255,255,255,0.06);
  }

  .dock-btn {
    width: 42px; height: 42px;
    border-radius: 10px;
    border: none;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background 0.15s, transform 0.1s;
    position: relative;
  }
  .dock-btn:hover { background: rgba(255,255,255,0.1); transform: scale(1.08); }
  .dock-btn svg { width: 26px; height: 26px; }

  /* ── Windows ── */
  .app-window {
    position: absolute;
    background: #2d2d2d;
    border-radius: 10px;
    box-shadow: 0 8px 40px rgba(0,0,0,0.55), 0 0 0 1px rgba(255,255,255,0.06);
    display: flex;
    flex-direction: column;
    overflow: hidden;
    min-width: 380px;
    min-height: 280px;
    z-index: 100;
  }

  .win-titlebar {
    height: 36px;
    background: #3a3a3a;
    display: flex;
    align-items: center;
    padding: 0 12px;
    cursor: default;
    flex-shrink: 0;
    border-bottom: 1px solid rgba(255,255,255,0.04);
  }
  .win-titlebar .title {
    color: #ccc;
    font-size: 13px;
    flex: 1;
    text-align: center;
    letter-spacing: 0.2px;
  }

  .win-close {
    width: 28px; height: 28px;
    border-radius: 50%;
    border: none;
    background: transparent;
    color: #aaa;
    font-size: 16px;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background 0.12s, color 0.12s;
  }
  .win-close:hover { background: #e74c3c; color: #fff; }

  .win-body { flex: 1; overflow: auto; display: flex; flex-direction: column; }

  /* ── Files App ── */
  #files-window { width: 620px; height: 420px; left: 120px; top: 80px; }

  .files-toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 14px;
    background: #353535;
    border-bottom: 1px solid rgba(255,255,255,0.05);
  }

  #files-up {
    width: 30px; height: 30px;
    border-radius: 6px;
    border: none;
    background: rgba(255,255,255,0.07);
    color: #ccc;
    font-size: 16px;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background 0.12s;
  }
  #files-up:hover { background: rgba(255,255,255,0.14); }

  #files-path {
    flex: 1;
    background: rgba(0,0,0,0.3);
    border: 1px solid rgba(255,255,255,0.08);
    border-radius: 6px;
    padding: 5px 12px;
    color: #e0e0e0;
    font-size: 13px;
    font-family: 'SF Mono', 'Fira Code', monospace;
    outline: none;
  }

  .files-list {
    flex: 1;
    overflow-y: auto;
    padding: 6px 8px;
  }

  .fs-item {
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 7px 12px;
    border-radius: 6px;
    cursor: pointer;
    color: #ddd;
    font-size: 13.5px;
    transition: background 0.1s;
  }
  .fs-item:hover { background: rgba(255,255,255,0.07); }

  .fs-icon { width: 20px; height: 20px; flex-shrink: 0; }
  .fs-icon.folder { color: #f0c040; }
  .fs-icon.file { color: #8ab4f8; }

  /* ── Notepad App ── */
  #notepad-window { width: 560px; height: 400px; left: 200px; top: 100px; }

  .notepad-toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 6px 12px;
    background: #353535;
    border-bottom: 1px solid rgba(255,255,255,0.05);
  }

  #new-tab {
    height: 28px;
    padding: 0 14px;
    border-radius: 6px;
    border: none;
    background: #e95420;
    color: #fff;
    font-size: 13px;
    cursor: pointer;
    transition: background 0.12s;
  }
  #new-tab:hover { background: #d14a1b; }

  #tabs {
    display: flex;
    gap: 2px;
    padding: 0 8px;
    background: #353535;
    border-bottom: 1px solid rgba(255,255,255,0.05);
    overflow-x: auto;
    flex-shrink: 0;
  }

  .tab {
    padding: 6px 18px;
    background: rgba(255,255,255,0.04);
    color: #aaa;
    font-size: 12.5px;
    border: none;
    cursor: pointer;
    border-radius: 6px 6px 0 0;
    transition: background 0.12s, color 0.12s;
    white-space: nowrap;
    max-width: 150px;
    overflow: hidden;
    text-overflow: ellipsis;
  }
  .tab:hover { background: rgba(255,255,255,0.08); color: #ddd; }
  .tab.active { background: #2d2d2d; color: #fff; }

  #editor-wrap { flex: 1; display: flex; flex-direction: column; overflow: hidden; }

  #editor {
    flex: 1;
    resize: none;
    border: none;
    outline: none;
    background: #2d2d2d;
    color: #e8e8e8;
    font-family: 'SF Mono', 'Fira Code', 'Consolas', monospace;
    font-size: 13.5px;
    line-height: 1.6;
    padding: 14px 16px;
    tab-size: 2;
  }

  /* ── Scrollbar ── */
  ::-webkit-scrollbar { width: 8px; }
  ::-webkit-scrollbar-track { background: transparent; }
  ::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.15); border-radius: 4px; }
  ::-webkit-scrollbar-thumb:hover { background: rgba(255,255,255,0.25); }

  /* ── Dragging hint ── */
  .app-window.dragging { opacity: 0.92; box-shadow: 0 14px 56px rgba(0,0,0,0.7); }
</style>
</head>
<body>

<!-- Desktop -->
<div id="desktop"></div>

<!-- Top Bar -->
<div id="topbar">
  <div class="left">
    <span style="font-weight:600;letter-spacing:0.5px;">Activities</span>
  </div>
  <div class="center" id="clock"></div>
  <div class="right">
    <span>🔊</span>
    <span>📶</span>
    <span>🔋</span>
  </div>
</div>

<!-- Dock / Taskbar -->
<div id="taskbar">
  <button id="open-files" class="dock-btn" title="Files">
    <svg viewBox="0 0 24 24" fill="none" stroke="#f0c040" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round">
      <path d="M22 19a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h5l2 3h9a2 2 0 0 1 2 2z"/>
    </svg>
  </button>
  <button id="open-notepad" class="dock-btn" title="Notepad">
    <svg viewBox="0 0 24 24" fill="none" stroke="#e95420" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round">
      <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/>
      <polyline points="14 2 14 8 20 8"/>
      <line x1="16" y1="13" x2="8" y2="13"/>
      <line x1="16" y1="17" x2="8" y2="17"/>
    </svg>
  </button>
</div>

<!-- Files Window -->
<div id="files-window" class="app-window" style="display:none;">
  <div class="win-titlebar">
    <span class="title">Files</span>
    <button class="win-close" title="Close">&times;</button>
  </div>
  <div class="win-body">
    <div class="files-toolbar">
      <button id="files-up" title="Up">↑</button>
      <input id="files-path" readonly value="/">
    </div>
    <div class="files-list" id="files-list"></div>
  </div>
</div>

<!-- Notepad Window -->
<div id="notepad-window" class="app-window" style="display:none;">
  <div class="win-titlebar">
    <span class="title">Notepad</span>
    <button class="win-close" title="Close">&times;</button>
  </div>
  <div class="win-body">
    <div class="notepad-toolbar">
      <button id="new-tab">+ New Tab</button>
    </div>
    <div id="tabs"></div>
    <div id="editor-wrap">
      <textarea id="editor" spellcheck="false"></textarea>
    </div>
  </div>
</div>

<script>
/* ════════════════════════════════════════
   Clock
   ════════════════════════════════════════ */
function updateClock() {
  const now = new Date();
  document.getElementById('clock').textContent =
    now.toLocaleDateString(undefined, { weekday:'short', month:'short', day:'numeric' }) + '  ' +
    now.toLocaleTimeString(undefined, { hour:'2-digit', minute:'2-digit' });
}
updateClock();
setInterval(updateClock, 10000);

/* ════════════════════════════════════════
   Window Management (dragging)
   ════════════════════════════════════════ */
let dragTarget = null, dragOffX = 0, dragOffY = 0;

document.querySelectorAll('.app-window').forEach(w => {
  const tb = w.querySelector('.win-titlebar');
  tb.addEventListener('mousedown', e => {
    if (e.target.classList.contains('win-close')) return;
    dragTarget = w;
    dragOffX = e.clientX - w.offsetLeft;
    dragOffY = e.clientY - w.offsetTop;
    w.classList.add('dragging');
    bringToFront(w);
  });
});

document.addEventListener('mousemove', e => {
  if (!dragTarget) return;
  let nx = e.clientX - dragOffX;
  let ny = e.clientY - dragOffY;
  // keep within viewport bounds roughly
  ny = Math.max(28, ny);
  dragTarget.style.left = nx + 'px';
  dragTarget.style.top = ny + 'px';
});

document.addEventListener('mouseup', () => {
  if (dragTarget) {
    dragTarget.classList.remove('dragging');
    dragTarget = null;
  }
});

function bringToFront(el) {
  const all = document.querySelectorAll('.app-window');
  let maxZ = 0;
  all.forEach(w => { const z = parseInt(getComputedStyle(w).zIndex)||0; if(z>maxZ) maxZ=z; });
  el.style.zIndex = maxZ + 1;
}

/* ════════════════════════════════════════
   Files App — Fake Filesystem
   ════════════════════════════════════════ */
const fs = {
  '/': ['bin','etc','home','usr','var'],
  '/bin': ['bash','cat','cp','ls','mkdir','mv','rm'],
  '/etc': ['hostname','hosts','passwd','fstab','resolv.conf'],
  '/home': ['user'],
  '/home/user': ['Documents','Downloads','Pictures','.bashrc','.profile'],
  '/home/user/Documents': ['readme.txt','notes.md','todo.org'],
  '/home/user/Downloads': ['ubuntu-24.04.iso','archive.tar.gz'],
  '/home/user/Pictures': ['wallpaper.png','screenshot.png'],
  '/usr': ['bin','lib','share'],
  '/usr/bin': ['gcc','python3','node','vim'],
  '/usr/lib': ['libc.so','libssl.so'],
  '/usr/share': ['man','doc'],
  '/var': ['log','tmp','cache'],
  '/var/log': ['syslog','auth.log'],
  '/var/tmp': [],
  '/var/cache': []
};

let currentPath = '/';

function getItems(path) { return fs[path] || []; }
function getParent(p) { if (p === '/') return null; const i = p.lastIndexOf('/'); return i === 0 ? '/' : p.slice(0, i); }

const folderIcons = `<svg class="fs-icon folder" viewBox="0 0 24 24" fill="#f0c040"><path d="M10 4H4a2 2 0 0 0-2 2v12a2 2 0 0 0 2 2h16a2 2 0 0 0 2-2V8a2 2 0 0 0-2-2h-8l-2-2z"/></svg>`;
const fileIcons = `<svg class="fs-icon file" viewBox="0 0 24 24" fill="#8ab4f8"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8" fill="none" stroke="#8ab4f8"/></svg>`;

function renderFiles() {
  const list = document.getElementById('files-list');
  list.innerHTML = '';
  const items = getItems(currentPath);
  if (items.length === 0) {
    const empty = document.createElement('div');
    empty.style.cssText = 'color:#777;font-size:13px;padding:24px;text-align:center;';
    empty.textContent = '(empty directory)';
    list.appendChild(empty);
    return;
  }
  // sort: folders first, then files alphabetically
  const sorted = items.slice().sort((a,b) => {
    const aIsDir = fs[currentPath + '/' + a] !== undefined;
    const bIsDir = fs[currentPath + '/' + b] !== undefined;
    if (aIsDir && !bIsDir) return -1;
    if (!aIsDir && bIsDir) return 1;
    return a.localeCompare(b);
  });

  sorted.forEach(name => {
    const isDir = fs[currentPath + '/' + name] !== undefined;
    const el = document.createElement('div');
    el.className = 'fs-item';
    el.innerHTML = (isDir ? folderIcons : fileIcons) + `<span>${name}</span>`;

    if (isDir) {
      el.addEventListener('dblclick', () => {
        currentPath = currentPath === '/' ? '/' + name : currentPath + '/' + name;
        document.getElementById('files-path').value = currentPath;
        renderFiles();
      });
    }
    list.appendChild(el);
  });

  document.getElementById('files-path').value = currentPath;
}

document.getElementById('open-files').addEventListener('click', () => {
  const w = document.getElementById('files-window');
  w.style.display = 'flex';
  bringToFront(w);
  renderFiles();
});

document.getElementById('files-up').addEventListener('click', () => {
  const parent = getParent(currentPath);
  if (parent) { currentPath = parent; renderFiles(); }
});

// Close button for files window
document.querySelector('#files-window .win-close').addEventListener('click', function() {
  this.closest('.app-window').style.display = 'none';
});

/* ════════════════════════════════════════
   Notepad App — Tabbed, Persistent
   ════════════════════════════════════════ */
const STORAGE_KEY = 'notepad-tabs-v1';

function loadTabs() {
  try { return JSON.parse(localStorage.getItem(STORAGE_KEY)) || []; } catch(e) { return []; }
}

function saveTabs(tabs) {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(tabs));
}

let tabs = loadTabs();
let activeIdx = Math.max(0, (tabs.length > 0 ? tabs.length - 1 : -1));

// If no tabs exist yet, create one default tab
if (tabs.length === 0) {
  tabs.push({ name: 'Untitled', content: '' });
  activeIdx = 0;
}

function renderTabs() {
  const container = document.getElementById('tabs');
  container.innerHTML = '';
  tabs.forEach((tab, i) => {
    const el = document.createElement('button');
    el.className = 'tab' + (i === activeIdx ? ' active' : '');
    el.textContent = tab.name;
    el.addEventListener('click', () => {
      // Save current before switching
      if (tabs[activeIdx]) tabs[activeIdx].content = document.getElementById('editor').value;
      activeIdx = i;
      renderTabs();
      document.getElementById('editor').value = tabs[i].content || '';
    });
    container.appendChild(el);
  });
}

function switchEditor() {
  if (tabs[activeIdx]) {
    document.getElementById('editor').value = tabs[activeIdx].content || '';
  } else {
    document.getElementById('editor').value = '';
  }
}

document.getElementById('new-tab').addEventListener('click', () => {
  // Save current tab content first
  if (tabs[activeIdx]) tabs[activeIdx].content = document.getElementById('editor').value;
  const idx = tabs.length;
  tabs.push({ name: 'Untitled-' + (idx + 1), content: '' });
  activeIdx = idx;
  renderTabs();
  switchEditor();
});

// Auto-save on typing
document.getElementById('editor').addEventListener('input', () => {
  if (tabs[activeIdx]) tabs[activeIdx].content = document.getElementById('editor').value;
  saveTabs(tabs);
});

function persist() { saveTabs(tabs); }

document.getElementById('open-notepad').addEventListener('click', () => {
  const w = document.getElementById('notepad-window');
  w.style.display = 'flex';
  bringToFront(w);
  renderTabs();
  switchEditor();
});

// Close button for notepad window — save before hiding
document.querySelector('#notepad-window .win-close').addEventListener('click', function() {
  persist();
  this.closest('.app-window').style.display = 'none';
});

// Initial render
renderTabs();
switchEditor();
</script>
</body>
</html>
